        req1.put(GemColor.WHITE, 3);
        req1.put(GemColor.BLUE, 3);
        noble1 = new Noble(1, "Queen", req1);

        Map<GemColor, Integer> req2 = new EnumMap<>(GemColor.class);
        req2.put(GemColor.RED, 4);
        noble2 = new Noble(2, "King", req2);

        claimableNobles = new ArrayList<>();
        claimableNobles.add(noble1);
        claimableNobles.add(noble2);

        List<Noble> availableNobles = new ArrayList<>(claimableNobles);
        state = new GameState(List.of(player), market, bank, availableNobles, 15);
