        Card card = buildCard(1, 0, GemColor.WHITE);
        AIAction actionA = new AIAction(ActionType.PURCHASE_CARD, card, false, null, "strategy A");
        AIAction actionB = new AIAction(ActionType.RESERVE_CARD, card, false, null, "strategy B");

        AIStrategy strategyA = new StubStrategy(actionA, noble1, new GemCollection());
