    @Test
    @DisplayName("Swapping strategy reference changes decision outcome")
    void polymorphism_strategySwap() {
        AIAction buyAction = new AIAction(ActionType.PURCHASE_CARD, buildCard(1, 0, GemColor.WHITE),
                false, null, "buy");
        AIAction takeAction = new AIAction(ActionType.TAKE_THREE_DIFFERENT, null, false,
                new GemCollection().add(GemColor.WHITE, 1).add(GemColor.BLUE, 1).add(GemColor.GREEN, 1),
                "take");

        AIStrategy current = new StubStrategy(buyAction, noble1, new GemCollection());
        assertEquals(ActionType.PURCHASE_CARD, current.decideAction(state, player).getActionType());

        current = new StubStrategy(takeAction, noble1, new GemCollection());
        assertEquals(ActionType.TAKE_THREE_DIFFERENT, current.decideAction(state, player).getActionType());
    }

