    private Card buildCard(int level, int points, GemColor bonus) {
        Map<GemColor, Integer> costMap = new EnumMap<>(GemColor.class);
        costMap.put(GemColor.WHITE, 1);
        return new Card(level, points, bonus, new Cost(costMap));
    }

    private List<Card> buildCardList(int level, int count) {
        List<Card> cards = new ArrayList<>();
        GemColor[] colors = {GemColor.WHITE, GemColor.BLUE, GemColor.GREEN, GemColor.RED, GemColor.BLACK};
        for (int i = 0; i < count; i++) {
            Map<GemColor, Integer> costMap = new EnumMap<>(GemColor.class);
            costMap.put(colors[i % colors.length], 1 + (i % 3));
            cards.add(new Card(level, i % 4, colors[i % colors.length], new Cost(costMap)));
        }
        return cards;
    }
